content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯的拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi de ná tiě, kě yǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 de5 na2 tie3, ke3 yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩你，可以給我一個袋子嗎？",
      "pinyin": "Má fan nǐ, kě yǐ gěi wǒ yī ge dài zi ma?",
      "pinyin_numeric": "ma2 fan5 ni3, ke3 yi3 gei3 wo3 yi1 ge5 dai4 zi5 ma0?",
      "translation_en": "Excuse me, can you give me a bag?",
      "translation_ko": "실례합니다, 봉투 하나 주실 수 있나요?"
    },
    {
      "text": "不好意思，可以幫我加珍珠嗎？",
      "pinyin": "Bù hǎo yì si, kě yǐ bāng wǒ jiā zhēn zhū ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si5, ke3 yi3 bang1 wo3 jia1 zhen1 zhu1 ma0?",
      "translation_en": "Excuse me, can you add boba for me?",
      "translation_ko": "죄송합니다, 타피오카 펄을 추가해 주실 수 있나요?"
    },
    {
      "text": "店員，可以給我看菜單嗎？",
      "pinyin": "Diàn yuán, kě yǐ gěi wǒ kàn cài dān ma?",
      "pinyin_numeric": "dian4 yuan2, ke3 yi3 gei3 wo3 kan4 cai4 dan1 ma0?",
      "translation_en": "Shop assistant, can you show me the menu?",
      "translation_ko": "점원님, 메뉴판을 보여 주실 수 있나요?"
    },
    {
      "text": "我想要一杯中杯的紅茶，半糖，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi zhōng bēi de hóng chá, bàn táng, kě yǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 zhong1 bei1 de5 hong2 cha2, ban4 tang2, ke3 yi3 ma0?",
      "translation_en": "I would like a medium black tea, half sugar, okay?",
      "translation_ko": "중간 컵 홍차 반 당을 원하는데 괜찮을까요?"
    },
    {
      "text": "不好意思，可以給我一根吸管嗎？",
      "pinyin": "Bù hǎo yì si, kě yǐ gěi wǒ yī gēn xī guǎn ma?",
      "pinyin_numeric": "bu4 hao3 yi4 si5, ke3 yi3 gei3 wo3 yi1 gen1 xi1 guan3 ma0?",
      "translation_en": "Excuse me, can you give me a straw?",
      "translation_ko": "죄송합니다, 빨대 하나 주실 수 있나요?"
    },
    {
      "text": "麻煩你，可以幫我外帶嗎？",
      "pinyin": "Má fan nǐ, kě yǐ bāng wǒ wài dài ma?",
      "pinyin_numeric": "ma2 fan5 ni3, ke3 yi3 bang1 wo3 wai4 dai4 ma0?",
      "translation_en": "Excuse me, can you make it for takeout?",
      "translation_ko": "실례합니다, 포장해 주실 수 있나요?"
    },
    {
      "text": "我想要一杯大杯的綠茶，去冰，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi dà bēi de lǜ chá, qù bīng, kě yǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 da4 bei1 de5 lü4 cha2, qu4 bing1, ke3 yi3 ma0?",
      "translation_en": "I would like a large green tea, no ice, okay?",
      "translation_ko": "큰 컵 녹차 얼음 없이 원하는데 괜찮을까요?"
    },
    {
      "text": "店員，可以給我發票嗎？",
      "pinyin": "Diàn yuán, kě yǐ gěi wǒ fā piào ma?",
      "pinyin_numeric": "dian4 yuan2, ke3 yi3 gei3 wo3 fa1 piao4 ma0?",
      "translation_en": "Shop assistant, can you give me the receipt?",
      "translation_ko": "점원님, 영수증 주실 수 있나요?"
    },
    {
      "text": "不好意思，可以再說一次嗎？請慢一點。",
      "pinyin": "Bù hǎo yì si, kě yǐ zài shuō yī cì ma? Qǐng màn yī diǎn.",
      "pinyin_numeric": "bu4 hao3 yi4 si5, ke3 yi3 zai4 shuo1 yi1 ci4 ma0? qing3 man4 yi1 dian3.",
      "translation_en": "Excuse me, can you say it again? Please speak slowly.",
      "translation_ko": "죄송합니다, 한 번 더 말씀해 주실 수 있나요? 천천히 부탁드립니다."
    }
  ]
}
